import { useEffect, useState } from "react";
import { getFacultyQuestions } from "../../api/questionApi";

function FacultyQuestionnaire() {

  const [questions, setQuestions] =
    useState([]);

  useEffect(() => {

    const loadQuestions =
      async () => {

        try {

          const data =
            await getFacultyQuestions();

          setQuestions(data);

        } catch (error) {

          console.error(error);

        }
      };

    loadQuestions();

  }, []);

  return (
    <div
      style={{
        padding: "30px"
      }}
    >
      <h1>
        Faculty Questionnaire
      </h1>

      {questions.map((q) => (

        <div
          key={q._id}
          style={{
            background: "#fff",
            padding: "15px",
            marginBottom: "15px",
            borderRadius: "10px",
            boxShadow:
              "0 2px 6px rgba(0,0,0,0.1)"
          }}
        >
          <h3>
            Q{q.questionNo}
          </h3>

          <p>
            {q.question}
          </p>

          <input
            type="text"
            placeholder="Enter Answer"
            style={{
              width: "100%",
              padding: "10px"
            }}
          />
        </div>

      ))}
    </div>
  );
}

export default FacultyQuestionnaire;
